FILES = {'src/frontend/command_center/modern/claire_dashboard_decongestion.css': '/*\n  Claire v17.62.1 — Dashboard Decongestion Hotfix\n\n  Purpose:\n  - Stop the search bar from covering the dashboard.\n  - Remove unnecessary nested panel scrollbars.\n  - Let portals expand so content is readable.\n  - Keep right-side/live rails scrollable without choking main content.\n  - Improve workspace spacing without changing runtime truth logic.\n*/\n\n:root {\n  --claire-readable-width: 1860px;\n  --claire-left-rail-width: 392px;\n  --claire-right-rail-width: 430px;\n  --claire-content-gap: 22px;\n}\n\n/* Search should not float across the middle of the operating environment. */\n.claire-dashboard-search-shell {\n  position: fixed !important;\n  top: 14px !important;\n  right: 22px !important;\n  left: auto !important;\n  transform: none !important;\n  width: min(560px, calc(100vw - 470px)) !important;\n  z-index: 10020 !important;\n}\n\n.claire-dashboard-search-box {\n  min-height: 44px !important;\n  padding: 8px 12px !important;\n  border-radius: 16px !important;\n}\n\n.claire-dashboard-search-label {\n  font-size: 9px !important;\n  letter-spacing: .14em !important;\n}\n\n.claire-dashboard-search-results {\n  max-height: min(58vh, 520px) !important;\n}\n\n/* Do not add fake body padding because the search bar is now docked to the right. */\nbody.claire-search-mounted {\n  padding-top: 0 !important;\n}\n\n/* Remove nested scroll congestion from primary portals. */\n.portal,\n.claire-portal,\n.surface,\n.claire-surface,\n.dashboard-panel,\n.claire-panel,\n.stage-card,\n.loop-card,\n.source-card,\n.route-col,\n.validation-node,\n.roadmap-card,\n.claire-validation-authority-panel,\n.claire-memory-panel,\n#claire-validation-authority-panel,\n#claire-verified-memory-panel {\n  max-height: none !important;\n  overflow: visible !important;\n  resize: none !important;\n}\n\n/* Main sections need breathing room. */\nsection,\narticle,\n.dashboard-panel,\n.claire-panel,\n.claire-validation-authority-panel,\n.claire-memory-panel,\n.stage-card,\n.loop-card,\n.source-card,\n.route-col,\n.validation-node,\n.roadmap-card {\n  padding-block: clamp(16px, 1.4vw, 26px);\n}\n\n/* Widen the operating environment where the display allows it. */\nmain,\n#app,\n#workspace,\n#main-workspace,\n.command-center,\n.operating-environment,\n.claire-operating-environment,\n.claire-shell,\n.dashboard-shell {\n  width: min(100%, var(--claire-readable-width)) !important;\n  max-width: var(--claire-readable-width) !important;\n}\n\n/* Cards should not compress into tiny unreadable columns. */\n.portal-grid,\n.surface-grid,\n.dashboard-grid,\n.cards-grid,\n.panel-grid,\n.route-grid {\n  grid-template-columns: repeat(auto-fit, minmax(340px, 1fr)) !important;\n  gap: var(--claire-content-gap) !important;\n}\n\n.lifecycle-grid,\n.stage-grid,\n#lifecycle-grid,\n#stage-grid {\n  grid-template-columns: repeat(auto-fit, minmax(280px, 1fr)) !important;\n  gap: 16px !important;\n}\n\n/* Validation and memory portals deserve full-width readable blocks. */\n#claire-validation-authority-panel,\n#claire-verified-memory-panel,\n.claire-validation-authority-panel,\n.claire-memory-panel {\n  width: 100% !important;\n  margin: 22px 0 !important;\n}\n\n/* Their internal grids should breathe too. */\n.claire-validation-grid,\n.claire-memory-grid {\n  grid-template-columns: repeat(auto-fit, minmax(210px, 1fr)) !important;\n  gap: 14px !important;\n}\n\n.claire-validation-checks,\n.claire-memory-reasons {\n  grid-template-columns: repeat(auto-fit, minmax(320px, 1fr));\n  gap: 12px !important;\n}\n\n/* Keep the live rail readable but constrained. */\n.right-rail,\n.live-rail,\n.narrative-rail,\naside[class*="rail"],\nsection[class*="rail"] {\n  max-height: calc(100vh - 190px) !important;\n  overflow-y: auto !important;\n  overflow-x: hidden !important;\n  scrollbar-width: thin;\n}\n\n/* Side navigation can scroll independently without stealing the whole page. */\n.nav-sidebar,\n.side-nav,\n.sidebar,\naside[class*="side"] {\n  max-height: calc(100vh - 28px) !important;\n  overflow-y: auto !important;\n  overflow-x: hidden !important;\n  scrollbar-width: thin;\n}\n\n/* Current screenshot shows bottom proof bar labels squeezed. */\n.proofbar,\n.status-rail,\n.bottom-rail,\n.claire-proofbar,\n[class*="proof"],\n[class*="status-rail"] {\n  min-height: auto !important;\n  overflow: visible !important;\n  flex-wrap: wrap !important;\n  gap: 8px !important;\n}\n\n/* Text and labels must remain readable. */\np,\nli,\nspan,\ntd,\nth,\nbutton,\nlabel,\ninput,\ntextarea,\nselect,\n.claire-validation-check-details,\n.claire-memory-reason,\n.claire-dashboard-search-result-snippet {\n  line-height: 1.55 !important;\n  overflow-wrap: anywhere !important;\n}\n\n/* Long runtime/evidence data should scroll only inside explicit raw-data blocks. */\npre,\ncode,\n.json-viewer,\n.raw-json,\n.output-preview,\n.runtime-truth,\n.validation-report,\n.memory-report,\n.evidence-index {\n  white-space: pre-wrap !important;\n  overflow-wrap: anywhere !important;\n  overflow-x: auto !important;\n  max-width: 100% !important;\n}\n\n/* Decongest the top-right badges by keeping them compact. */\n.badge,\n[class*="badge"],\n[class*="pill"] {\n  white-space: normal !important;\n}\n\n/* Focus mode: useful on smaller displays. It hides rails without removing functionality. */\nbody.claire-focus-mode .nav-sidebar,\nbody.claire-focus-mode .side-nav,\nbody.claire-focus-mode .sidebar,\nbody.claire-focus-mode .right-rail,\nbody.claire-focus-mode .live-rail,\nbody.claire-focus-mode .narrative-rail,\nbody.claire-focus-mode aside[class*="rail"],\nbody.claire-focus-mode aside[class*="side"] {\n  display: none !important;\n}\n\nbody.claire-focus-mode main,\nbody.claire-focus-mode #app,\nbody.claire-focus-mode #workspace,\nbody.claire-focus-mode #main-workspace,\nbody.claire-focus-mode .command-center,\nbody.claire-focus-mode .operating-environment,\nbody.claire-focus-mode .claire-operating-environment,\nbody.claire-focus-mode .claire-shell,\nbody.claire-focus-mode .dashboard-shell {\n  width: min(100%, 1540px) !important;\n  max-width: 1540px !important;\n  margin-left: auto !important;\n  margin-right: auto !important;\n}\n\n/* A small control for focus mode, not a new feature surface. */\n.claire-view-mode-toggle {\n  position: fixed;\n  top: 70px;\n  right: 22px;\n  z-index: 10019;\n  border: 1px solid rgba(0, 212, 255, 0.28);\n  border-radius: 999px;\n  background: rgba(5, 10, 20, 0.84);\n  color: #8eeaff;\n  font: 700 11px/1 Inter, system-ui, sans-serif;\n  letter-spacing: .08em;\n  text-transform: uppercase;\n  padding: 9px 12px;\n  backdrop-filter: blur(14px);\n  cursor: pointer;\n}\n\n.claire-view-mode-toggle:hover {\n  border-color: rgba(0, 212, 255, 0.6);\n  background: rgba(0, 212, 255, 0.10);\n}\n\n/* Large displays: preserve three-zone shell but give center more space. */\n@media (min-width: 1500px) {\n  .claire-dashboard-search-shell {\n    width: 610px !important;\n  }\n\n  .portal-grid,\n  .surface-grid,\n  .dashboard-grid,\n  .cards-grid,\n  .panel-grid,\n  .route-grid {\n    grid-template-columns: repeat(auto-fit, minmax(380px, 1fr)) !important;\n  }\n}\n\n/* Medium displays: search becomes compact and panels stack more cleanly. */\n@media (max-width: 1320px) {\n  .claire-dashboard-search-shell {\n    top: 10px !important;\n    right: 12px !important;\n    width: min(480px, calc(100vw - 360px)) !important;\n  }\n\n  .claire-dashboard-search-label {\n    display: none !important;\n  }\n\n  .portal-grid,\n  .surface-grid,\n  .dashboard-grid,\n  .cards-grid,\n  .panel-grid,\n  .route-grid {\n    grid-template-columns: repeat(auto-fit, minmax(310px, 1fr)) !important;\n  }\n}\n\n/* Small displays: put search in normal top width and make all portals single-column. */\n@media (max-width: 920px) {\n  .claire-dashboard-search-shell {\n    position: sticky !important;\n    top: 8px !important;\n    right: auto !important;\n    left: auto !important;\n    width: calc(100% - 20px) !important;\n    margin: 8px auto 12px auto !important;\n    transform: none !important;\n  }\n\n  .claire-view-mode-toggle {\n    position: sticky;\n    top: 64px;\n    right: auto;\n    margin: 0 10px 10px auto;\n    display: block;\n    width: fit-content;\n  }\n\n  .portal-grid,\n  .surface-grid,\n  .dashboard-grid,\n  .cards-grid,\n  .panel-grid,\n  .route-grid,\n  .lifecycle-grid,\n  .stage-grid,\n  #lifecycle-grid,\n  #stage-grid,\n  .claire-validation-grid,\n  .claire-memory-grid,\n  .claire-validation-checks,\n  .claire-memory-reasons {\n    grid-template-columns: 1fr !important;\n  }\n\n  .right-rail,\n  .live-rail,\n  .narrative-rail,\n  aside[class*="rail"] {\n    max-height: none !important;\n    overflow: visible !important;\n  }\n}\n', 'src/frontend/command_center/modern/claire_dashboard_search.js': '(function () {\n  "use strict";\n\n  const LOCAL_JSON_PATHS = [\n    "dashboard_search_index.json",\n    "dashboard_architecture_map.json",\n    "lifecycle_stage_registry.json",\n    "runtime_surface_registry.json",\n    "route_surface_registry.json",\n    "runtime_truth_contract.json",\n    "runtime_truth_status.json",\n    "validation_authority_status.json",\n    "evidence_traceability_status.json",\n    "verified_memory_status.json",\n    "recursive_feedback_status.json",\n    "dashboard_search_contract.json",\n    "intelligence_command_contract.json",\n    "../../../exports/latest/dashboard_search_index.json",\n    "../../../exports/latest/dashboard_runtime_truth.json",\n    "../../../exports/latest/validation_authority_report.json",\n    "../../../exports/latest/evidence_traceability_index.json",\n    "../../../exports/latest/verified_memory_gate_report.json",\n    "../../../exports/latest/recursive_feedback_gate_report.json",\n    "exports/latest/dashboard_search_index.json",\n    "exports/latest/dashboard_runtime_truth.json",\n    "exports/latest/validation_authority_report.json",\n    "exports/latest/evidence_traceability_index.json",\n    "exports/latest/verified_memory_gate_report.json",\n    "exports/latest/recursive_feedback_gate_report.json"\n  ];\n\n  const state = {\n    documents: [],\n    selectedIndex: -1,\n    lastQuery: ""\n  };\n\n  function escapeHtml(value) {\n    return String(value ?? "")\n      .replace(/&/g, "&amp;")\n      .replace(/</g, "&lt;")\n      .replace(/>/g, "&gt;")\n      .replace(/"/g, "&quot;");\n  }\n\n  function normalizeText(value) {\n    return String(value ?? "").replace(/\\s+/g, " ").trim();\n  }\n\n  function flattenJson(value, prefix = "") {\n    const rows = [];\n    function walk(node, path) {\n      if (node === null || node === undefined) return;\n      if (Array.isArray(node)) {\n        node.forEach((item, index) => walk(item, `${path}[${index}]`));\n        return;\n      }\n      if (typeof node === "object") {\n        Object.entries(node).forEach(([key, item]) => walk(item, path ? `${path}.${key}` : key));\n        return;\n      }\n      rows.push(`${path}: ${String(node)}`);\n    }\n    walk(value, prefix);\n    return rows.join("\\n");\n  }\n\n  async function fetchJson(path) {\n    try {\n      const response = await fetch(path, { cache: "no-store" });\n      if (!response.ok) return null;\n      return await response.json();\n    } catch (_) {\n      return null;\n    }\n  }\n\n  function addDocument(doc) {\n    const key = `${doc.type}:${doc.path}:${doc.title}`;\n    if (state.documents.some((existing) => `${existing.type}:${existing.path}:${existing.title}` === key)) return;\n    state.documents.push(doc);\n  }\n\n  function collectVisibleSections() {\n    const selectors = [\n      "section",\n      "article",\n      ".portal",\n      ".claire-portal",\n      ".surface",\n      ".claire-surface",\n      ".dashboard-panel",\n      ".claire-panel",\n      ".stage-card",\n      ".route-col",\n      ".validation-node",\n      ".roadmap-card",\n      "#claire-validation-authority-panel",\n      "#claire-verified-memory-panel"\n    ];\n\n    const nodes = Array.from(document.querySelectorAll(selectors.join(",")));\n    const seen = new Set();\n\n    nodes.forEach((node, index) => {\n      if (!node || seen.has(node)) return;\n      seen.add(node);\n\n      const text = normalizeText(node.innerText || node.textContent || "");\n      if (!text || text.length < 16) return;\n\n      if (!node.id) node.id = `claire-search-section-${index + 1}`;\n\n      const titleNode = node.querySelector("h1,h2,h3,.section-title,.claire-validation-title,.claire-memory-title");\n      const title = normalizeText(\n        titleNode?.innerText ||\n        titleNode?.textContent ||\n        node.getAttribute("aria-label") ||\n        node.id ||\n        `Dashboard Surface ${index + 1}`\n      );\n\n      addDocument({\n        type: "visible_surface",\n        title,\n        path: `#${node.id}`,\n        text,\n        targetId: node.id\n      });\n    });\n  }\n\n  function ingestDashboardSearchIndex(indexJson, path) {\n    const docs = Array.isArray(indexJson?.documents) ? indexJson.documents : [];\n    docs.forEach((doc) => {\n      if (doc.status && doc.status !== "indexed") return;\n      addDocument({\n        type: "dashboard_index",\n        title: doc.title || doc.path || path,\n        path: doc.path || path,\n        text: doc.text || (Array.isArray(doc.terms) ? doc.terms.join(" ") : ""),\n        json: doc\n      });\n    });\n  }\n\n  async function collectJsonDocuments() {\n    const uniquePaths = [...new Set(LOCAL_JSON_PATHS)];\n    for (const path of uniquePaths) {\n      const json = await fetchJson(path);\n      if (!json) continue;\n\n      if (json.schema === "claire.dashboard_intelligence_index.v1") {\n        ingestDashboardSearchIndex(json, path);\n      }\n\n      const text = flattenJson(json);\n      if (!text) continue;\n\n      addDocument({\n        type: "runtime_or_contract_json",\n        title: path.split("/").pop() || path,\n        path,\n        text,\n        json\n      });\n    }\n  }\n\n  function scoreDocument(doc, queryParts) {\n    const haystack = `${doc.title}\\n${doc.path}\\n${doc.text}`.toLowerCase();\n    let score = 0;\n    for (const part of queryParts) {\n      if (!part) continue;\n      if (doc.title.toLowerCase().includes(part)) score += 14;\n      if (doc.path.toLowerCase().includes(part)) score += 7;\n      score += Math.min(haystack.split(part).length - 1, 14);\n    }\n    return score;\n  }\n\n  function snippet(text, queryParts) {\n    const clean = normalizeText(text);\n    const lower = clean.toLowerCase();\n    let index = -1;\n    for (const part of queryParts) {\n      index = lower.indexOf(part);\n      if (index >= 0) break;\n    }\n    if (index < 0) return clean.slice(0, 220);\n    const start = Math.max(0, index - 80);\n    const end = Math.min(clean.length, index + 180);\n    return `${start > 0 ? "…" : ""}${clean.slice(start, end)}${end < clean.length ? "…" : ""}`;\n  }\n\n  function search(query) {\n    const parts = normalizeText(query).toLowerCase().split(" ").filter(Boolean);\n    if (!parts.length) return [];\n    return state.documents\n      .map((doc) => ({ doc, score: scoreDocument(doc, parts), snippet: snippet(doc.text, parts) }))\n      .filter((item) => item.score > 0)\n      .sort((a, b) => b.score - a.score)\n      .slice(0, 12);\n  }\n\n  function ensureStyles() {\n    if (document.getElementById("claire-dashboard-search-style")) return;\n    const style = document.createElement("style");\n    style.id = "claire-dashboard-search-style";\n    style.textContent = `\n      .claire-dashboard-search-shell {\n        position: fixed;\n        top: 14px;\n        right: 22px;\n        z-index: 10020;\n        width: min(560px, calc(100vw - 470px));\n        color: #e2e8f0;\n        font-family: Inter, system-ui, sans-serif;\n      }\n      .claire-dashboard-search-box {\n        display: flex;\n        align-items: center;\n        gap: 10px;\n        border: 1px solid rgba(0, 212, 255, 0.34);\n        border-radius: 16px;\n        padding: 8px 12px;\n        background: rgba(5, 10, 20, 0.88);\n        backdrop-filter: blur(18px);\n        box-shadow: 0 0 24px rgba(0, 212, 255, 0.10);\n      }\n      .claire-dashboard-search-label {\n        font-family: Orbitron, Inter, system-ui, sans-serif;\n        color: #00d4ff;\n        font-size: 9px;\n        font-weight: 800;\n        letter-spacing: .14em;\n        text-transform: uppercase;\n        white-space: nowrap;\n      }\n      .claire-dashboard-search-input {\n        flex: 1;\n        min-width: 0;\n        border: 0;\n        outline: 0;\n        background: transparent;\n        color: #f8fafc;\n        font-size: 13px;\n        line-height: 1.4;\n      }\n      .claire-dashboard-search-input::placeholder { color: #64748b; }\n      .claire-dashboard-search-kbd {\n        border: 1px solid rgba(148, 163, 184, 0.24);\n        border-radius: 8px;\n        padding: 3px 7px;\n        color: #94a3b8;\n        font-size: 10px;\n        white-space: nowrap;\n      }\n      .claire-dashboard-search-results {\n        display: none;\n        margin-top: 8px;\n        border: 1px solid rgba(0, 212, 255, 0.22);\n        border-radius: 18px;\n        background: rgba(3, 8, 18, 0.96);\n        backdrop-filter: blur(18px);\n        box-shadow: 0 22px 52px rgba(0, 0, 0, 0.34);\n        max-height: min(58vh, 520px);\n        overflow: auto;\n        padding: 8px;\n      }\n      .claire-dashboard-search-results.open { display: block; }\n      .claire-dashboard-search-result {\n        display: block;\n        width: 100%;\n        text-align: left;\n        border: 1px solid rgba(148, 163, 184, 0.12);\n        border-radius: 14px;\n        padding: 10px 12px;\n        margin: 6px 0;\n        background: rgba(15, 23, 42, 0.52);\n        color: #e2e8f0;\n        cursor: pointer;\n      }\n      .claire-dashboard-search-result:hover,\n      .claire-dashboard-search-result.active {\n        border-color: rgba(0, 212, 255, 0.45);\n        background: rgba(0, 212, 255, 0.08);\n      }\n      .claire-dashboard-search-result-title {\n        color: #f8fafc;\n        font-weight: 800;\n        font-size: 12px;\n        line-height: 1.4;\n        overflow-wrap: anywhere;\n      }\n      .claire-dashboard-search-result-meta {\n        margin-top: 2px;\n        color: #7dd3fc;\n        font-size: 10px;\n        letter-spacing: .06em;\n        text-transform: uppercase;\n        overflow-wrap: anywhere;\n      }\n      .claire-dashboard-search-result-snippet {\n        margin-top: 6px;\n        color: #94a3b8;\n        font-size: 12px;\n        line-height: 1.5;\n        overflow-wrap: anywhere;\n      }\n      .claire-dashboard-search-empty {\n        padding: 12px;\n        color: #94a3b8;\n        font-size: 12px;\n        line-height: 1.5;\n      }\n      .claire-search-highlight {\n        outline: 2px solid rgba(0, 212, 255, 0.75) !important;\n        box-shadow: 0 0 24px rgba(0, 212, 255, 0.22) !important;\n      }\n      @media (max-width: 920px) {\n        .claire-dashboard-search-shell {\n          position: sticky;\n          top: 8px;\n          right: auto;\n          left: auto;\n          width: calc(100% - 20px);\n          margin: 8px auto 12px auto;\n        }\n        .claire-dashboard-search-label,\n        .claire-dashboard-search-kbd {\n          display: none;\n        }\n      }\n    `;\n    document.head.appendChild(style);\n  }\n\n  function renderShell() {\n    if (document.getElementById("claire-dashboard-search-shell")) return;\n    ensureStyles();\n\n    const shell = document.createElement("div");\n    shell.id = "claire-dashboard-search-shell";\n    shell.className = "claire-dashboard-search-shell";\n    shell.innerHTML = `\n      <div class="claire-dashboard-search-box">\n        <div class="claire-dashboard-search-label">Claire Search</div>\n        <input id="claire-dashboard-search-input" class="claire-dashboard-search-input" autocomplete="off" spellcheck="false" placeholder="Search runtime, route, validation, memory…" aria-label="Claire dashboard search" />\n        <div class="claire-dashboard-search-kbd">Ctrl K</div>\n      </div>\n      <div id="claire-dashboard-search-results" class="claire-dashboard-search-results" role="listbox"></div>\n    `;\n    document.body.appendChild(shell);\n    document.body.classList.add("claire-search-mounted");\n\n    const input = document.getElementById("claire-dashboard-search-input");\n    const results = document.getElementById("claire-dashboard-search-results");\n\n    input.addEventListener("input", () => {\n      state.lastQuery = input.value;\n      state.selectedIndex = -1;\n      const query = input.value.trim();\n      if (!query) {\n        results.classList.remove("open");\n        results.innerHTML = "";\n        return;\n      }\n      renderResults(search(query));\n    });\n\n    input.addEventListener("focus", () => {\n      if (input.value.trim()) renderResults(search(input.value));\n    });\n\n    input.addEventListener("keydown", (event) => {\n      const buttons = Array.from(results.querySelectorAll(".claire-dashboard-search-result"));\n      if (event.key === "Escape") {\n        results.classList.remove("open");\n        input.blur();\n      } else if (event.key === "ArrowDown" && buttons.length) {\n        event.preventDefault();\n        state.selectedIndex = Math.min(buttons.length - 1, state.selectedIndex + 1);\n        markActive(buttons);\n      } else if (event.key === "ArrowUp" && buttons.length) {\n        event.preventDefault();\n        state.selectedIndex = Math.max(0, state.selectedIndex - 1);\n        markActive(buttons);\n      } else if (event.key === "Enter" && state.selectedIndex >= 0 && buttons[state.selectedIndex]) {\n        event.preventDefault();\n        buttons[state.selectedIndex].click();\n      }\n    });\n\n    document.addEventListener("keydown", (event) => {\n      const isMac = navigator.platform.toUpperCase().includes("MAC");\n      if ((isMac ? event.metaKey : event.ctrlKey) && event.key.toLowerCase() === "k") {\n        event.preventDefault();\n        input.focus();\n        input.select();\n      }\n    });\n\n    document.addEventListener("click", (event) => {\n      if (!shell.contains(event.target)) results.classList.remove("open");\n    });\n  }\n\n  function markActive(buttons) {\n    buttons.forEach((button, index) => {\n      button.classList.toggle("active", index === state.selectedIndex);\n      if (index === state.selectedIndex) button.scrollIntoView({ block: "nearest" });\n    });\n  }\n\n  function renderResults(items) {\n    const results = document.getElementById("claire-dashboard-search-results");\n    if (!results) return;\n    results.classList.add("open");\n\n    if (!items.length) {\n      results.innerHTML = `\n        <div class="claire-dashboard-search-empty">\n          No local matches. Generate runtime truth, validation, memory, and search index reports if this data should exist.\n        </div>\n      `;\n      return;\n    }\n\n    results.innerHTML = items.map((item, index) => `\n      <button class="claire-dashboard-search-result" data-index="${index}" type="button">\n        <div class="claire-dashboard-search-result-title">${escapeHtml(item.doc.title)}</div>\n        <div class="claire-dashboard-search-result-meta">${escapeHtml(item.doc.type)} · ${escapeHtml(item.doc.path)}</div>\n        <div class="claire-dashboard-search-result-snippet">${escapeHtml(item.snippet)}</div>\n      </button>\n    `).join("");\n\n    Array.from(results.querySelectorAll(".claire-dashboard-search-result")).forEach((button, index) => {\n      button.addEventListener("click", () => openResult(items[index].doc));\n    });\n  }\n\n  function openResult(doc) {\n    const results = document.getElementById("claire-dashboard-search-results");\n    if (results) results.classList.remove("open");\n\n    if (doc.targetId) {\n      const node = document.getElementById(doc.targetId);\n      if (node) {\n        document.querySelectorAll(".claire-search-highlight").forEach((el) => el.classList.remove("claire-search-highlight"));\n        node.classList.add("claire-search-highlight");\n        node.scrollIntoView({ behavior: "smooth", block: "start" });\n        window.setTimeout(() => node.classList.remove("claire-search-highlight"), 2600);\n      }\n      return;\n    }\n\n    const panel = ensureJsonResultPanel();\n    panel.innerHTML = `\n      <div class="claire-dashboard-search-result-title">Local truth file: ${escapeHtml(doc.title)}</div>\n      <div class="claire-dashboard-search-result-meta">${escapeHtml(doc.path)}</div>\n      <pre style="margin-top:10px; white-space:pre-wrap; overflow-wrap:anywhere; max-height:52vh; overflow:auto;">${escapeHtml(JSON.stringify(doc.json ?? doc.text, null, 2))}</pre>\n    `;\n    panel.scrollIntoView({ behavior: "smooth", block: "start" });\n  }\n\n  function ensureJsonResultPanel() {\n    let panel = document.getElementById("claire-search-json-result-panel");\n    if (!panel) {\n      panel = document.createElement("section");\n      panel.id = "claire-search-json-result-panel";\n      panel.className = "claire-dashboard-search-results open";\n      panel.style.display = "block";\n      panel.style.position = "relative";\n      panel.style.margin = "18px auto";\n      panel.style.width = "min(100%, 1180px)";\n      panel.style.transform = "none";\n      const mount = document.querySelector("main") || document.getElementById("app") || document.body;\n      mount.appendChild(panel);\n    }\n    return panel;\n  }\n\n  function installFocusToggle() {\n    if (document.getElementById("claire-view-mode-toggle")) return;\n    const button = document.createElement("button");\n    button.id = "claire-view-mode-toggle";\n    button.className = "claire-view-mode-toggle";\n    button.type = "button";\n    button.textContent = "Focus View";\n    button.title = "Toggle focused dashboard view";\n    button.addEventListener("click", () => {\n      document.body.classList.toggle("claire-focus-mode");\n      button.textContent = document.body.classList.contains("claire-focus-mode") ? "Full View" : "Focus View";\n    });\n    document.body.appendChild(button);\n  }\n\n  async function boot() {\n    renderShell();\n    installFocusToggle();\n\n    window.setTimeout(async () => {\n      state.documents = [];\n      collectVisibleSections();\n      await collectJsonDocuments();\n    }, 500);\n  }\n\n  if (document.readyState === "loading") {\n    document.addEventListener("DOMContentLoaded", boot);\n  } else {\n    boot();\n  }\n})();\n', 'docs/dashboard/v17.62.1_dashboard_decongestion.md': '# Claire v17.62.1 — Dashboard Decongestion Hotfix\n\n## Purpose\n\nThe v17.62 search/responsive layer made the dashboard too congested on wide desktop views. This hotfix repairs the layout without changing runtime logic.\n\n## Fixes\n\n- Search bar docked to top-right instead of floating across the middle.\n- Search dropdown no longer opens an empty message just from focus.\n- Primary portals no longer create unnecessary nested scrollbars.\n- Portals expand vertically so content is viewable.\n- Validation and memory panels get wider internal grids.\n- Route/lifecycle/card grids use larger readable minimum widths.\n- Side and live rails remain scrollable, but main content breathes.\n- Adds a small Focus View toggle to hide rails when the workspace feels crowded.\n\n## Files\n\n```text\nsrc/frontend/command_center/modern/claire_dashboard_decongestion.css\nsrc/frontend/command_center/modern/claire_dashboard_search.js\n```\n\nPatched:\n\n```text\nsrc/frontend/command_center/modern/index.html\n```\n\n## Scope\n\nNo runtime logic changed. No fake data added.\n', 'docs/update_packs/v17.62.1_dashboard_hotfix_pack.md': '# v17.62.1 Dashboard Hotfix Pack\n\n## Architecture section covered\n\n- Operating Environment usability\n- Dashboard readability\n- Command/search integration\n\n## Changes\n\nInstalled decongestion CSS and replaced the search script with a less intrusive version.\n\n## Verification\n\nAfter install:\n\n1. Hard refresh the dashboard with Ctrl+F5.\n2. Confirm the search bar is docked top-right instead of covering the main shell.\n3. Confirm portals expand and do not show multiple internal scrollbars.\n4. Confirm Ctrl+K focuses search.\n5. Confirm Focus View can temporarily hide rails.\n', 'data/build_manifests/v17.62.1_dashboard_decongestion_manifest.json': '{\n  "version": "17.62.1",\n  "name": "Dashboard Decongestion Hotfix",\n  "build_type": "dashboard_hotfix",\n  "purpose": "Repair dashboard congestion caused by search overlay and nested portal scroll behavior.",\n  "depends_on": [\n    "v17.62 Portal Resize + Dashboard Search Foundation"\n  ],\n  "installed_files": [\n    "docs/dashboard/v17.62.1_dashboard_decongestion.md",\n    "docs/update_packs/v17.62.1_dashboard_hotfix_pack.md",\n    "src/frontend/command_center/modern/claire_dashboard_decongestion.css",\n    "src/frontend/command_center/modern/claire_dashboard_search.js"\n  ],\n  "safety": {\n    "rollback_backups": true,\n    "launcher_path_preserved": "src/frontend/command_center/modern/index.html",\n    "runtime_logic_unchanged": true,\n    "no_fake_data": true\n  }\n}\n'}

CSS_FILE = "claire_dashboard_decongestion.css"
SEARCH_SCRIPT = "claire_dashboard_search.js"

def utc_stamp() -> str:
    return datetime.utcnow().strftime("%Y%m%d_%H%M%S")

def project_root() -> Path:
    return Path.cwd().resolve()

def backup_existing(root: Path, relative_path: str, backup_root: Path) -> None:
    target = root / relative_path
    if not target.exists():
        return
    backup_path = backup_root / relative_path
    backup_path.parent.mkdir(parents=True, exist_ok=True)
    if target.is_file():
        shutil.copy2(target, backup_path)
    elif target.is_dir():
        if backup_path.exists():
            shutil.rmtree(backup_path)
        shutil.copytree(target, backup_path)

def write_text(root: Path, relative_path: str, content: str, backup_root: Path) -> None:
    target = root / relative_path
    backup_existing(root, relative_path, backup_root)
    target.parent.mkdir(parents=True, exist_ok=True)
    target.write_text(content, encoding="utf-8")

def patch_index_html(root: Path, backup_root: Path) -> bool:
    index_rel = "src/frontend/command_center/modern/index.html"
    index_path = root / index_rel
    if not index_path.exists():
        return False

    html = index_path.read_text(encoding="utf-8", errors="ignore")
    original = html

    # Add decongestion CSS after any existing stylesheets so it overrides v17.62.
    if CSS_FILE not in html:
        css_tag = '\n<link rel="stylesheet" href="claire_dashboard_decongestion.css">\n'
        if "</head>" in html:
            html = html.replace("</head>", css_tag + "</head>", 1)
        else:
            html = css_tag + html

    # claire_dashboard_search.js already exists from v17.62 in most installs.
    # Do not duplicate the script tag; the file itself is replaced by this hotfix.
    if SEARCH_SCRIPT not in html:
        script_tag = '\n<script src="claire_dashboard_search.js"></script>\n'
        if "</body>" in html:
            html = html.replace("</body>", script_tag + "</body>", 1)
        else:
            html = html + script_tag

    if html != original:
        backup_existing(root, index_rel, backup_root)
        index_path.write_text(html, encoding="utf-8")

    return True

def write_install_record(root: Path, backup_root: Path, index_patched: bool) -> None:
    record = {
        "version": VERSION,
        "build_name": BUILD_NAME,
        "installed_at_utc": datetime.utcnow().isoformat() + "Z",
        "project_root": str(root),
        "backup_root": str(backup_root),
        "index_patched": index_patched,
        "files_written": sorted(FILES.keys()),
        "notes": [
            "Runtime logic unchanged.",
            "Dashboard search is docked and less intrusive.",
            "Primary portals expand instead of nested scrolling."
        ]
    }
    record_path = root / "data" / "build_manifests" / "v17.62.1_install_record.json"
    record_path.parent.mkdir(parents=True, exist_ok=True)
    record_path.write_text(json.dumps(record, indent=2) + "\n", encoding="utf-8")

def main() -> None:
    root = project_root()
    backup_root = root / "backups" / f"claire_v17_62_1_{utc_stamp()}"
    backup_root.mkdir(parents=True, exist_ok=True)

    for relative_path, content in FILES.items():
        write_text(root, relative_path, content, backup_root)

    index_patched = patch_index_html(root, backup_root)
    write_install_record(root, backup_root, index_patched)

    print("=" * 72)
    print(f"Claire v{VERSION} installed: {BUILD_NAME}")
    print("=" * 72)
    print(f"Project root: {root}")
    print(f"Backups:      {backup_root}")
    print("")
    print("Fixed dashboard congestion:")
    print("  - search docked to top-right")
    print("  - empty search dropdown no longer opens on focus")
    print("  - primary portals expand instead of nested scrolling")
    print("  - grids use larger readable widths")
    print("  - Focus View toggle added")
    print("")
    print("Hard refresh the dashboard with Ctrl+F5.")
    print("=" * 72)

if __name__ == "__main__":
    main()
